    "compassion":   { example: "The volunteer nurses showed great compassion towards the elderly patients in their care.", exampleJa: "ボランティア看護師たちは担当する高齢患者に対して大きな思いやりを示しました。" },
    "compatriot":   { example: "She cheered enthusiastically for her compatriot who was competing in the Olympic final.", exampleJa: "彼女はオリンピックの決勝に出場している同国人を熱心に応援しました。" },
    "compel":       { example: "The new evidence compelled the committee to immediately reopen the investigation.", exampleJa: "新たな証拠は委員会に直ちに調査を再開することを強いました。" },
    "compensate":   { example: "The airline agreed to compensate all passengers affected by the lengthy cancellation.", exampleJa: "航空会社は長時間の欠航の影響を受けたすべての乗客を補償することに同意しました。" },
    "competency":   { example: "The recruitment process assesses each candidate's competency across six key areas.", exampleJa: "採用プロセスは6つの主要分野における各候補者の能力を評価します。" },
    "competitiveness": { example: "The country's competitiveness in high-tech manufacturing has declined over the past decade.", exampleJa: "ハイテク製造業における国の競争力は過去10年間で低下しています。" },
    "compilation":  { example: "The album is a compilation of the band's greatest hits spanning twenty years.", exampleJa: "そのアルバムは20年にわたるバンドの最大のヒット曲のコンピレーションです。" },
    "compiler":     { example: "The compiler translates high-level source code into machine-readable binary instructions.", exampleJa: "コンパイラは高水準のソースコードをマシン可読のバイナリ命令に変換します。" },
    "complement":   { example: "A well-chosen wine should complement the flavours of the food, not overpower them.", exampleJa: "よく選ばれたワインは食べ物の風味を引き立てるべきであり圧倒するべきではありません。" },
    "compliance":   { example: "All staff members must complete the annual compliance training by the end of the month.", exampleJa: "すべてのスタッフは今月末までに年次コンプライアンス訓練を修了しなければなりません。" },
    "complication": { example: "A minor surgical complication arose but was quickly identified and successfully treated.", exampleJa: "小さな手術の合併症が発生しましたが迅速に発見され成功裏に治療されました。" },
