    "conditioning": { example: "Physical conditioning before a major marathon is as critical as the training itself.", exampleJa: "大きなマラソンの前の身体的コンディショニングはトレーニング自体と同様に重要です。" },
    "conducive":    { example: "A quiet and organised workspace is conducive to focused work and creative thinking.", exampleJa: "静かで整理された作業スペースは集中した仕事と創造的思考に好適です。" },
    "conduction":   { example: "Electrical conduction in metals occurs because electrons move freely through the material.", exampleJa: "金属での電気伝導は電子が材料を自由に移動するために起こります。" },
    "confide":      { example: "She chose to confide in her trusted colleague rather than seek formal HR support.", exampleJa: "彼女は正式な人事サポートを求めるよりも信頼できる同僚に打ち明けることを選びました。" },
    "confidential": { example: "All employee performance records are strictly confidential and accessible only to HR.", exampleJa: "すべての従業員の業績記録は厳密に機密であり人事部だけがアクセスできます。" },
    "configuration": { example: "The default software configuration can be adjusted in the advanced settings menu.", exampleJa: "デフォルトのソフトウェア設定は詳細設定メニューで調整できます。" },
    "confine":      { example: "The outbreak forced authorities to confine livestock movement to prevent disease spreading.", exampleJa: "感染症の発生により当局は病気の拡散を防ぐために家畜の移動を制限することを強いられました。" },
    "confinement":  { example: "Prolonged solitary confinement has been shown to cause lasting psychological damage.", exampleJa: "長期的な独房監禁は永続的な心理的ダメージを引き起こすことが示されています。" },
    "confines":     { example: "Within the strict confines of the tiny apartment, she found remarkable ways to stay creative.", exampleJa: "狭いアパートの厳しい制約の中で彼女は創造性を保つ素晴らしい方法を見つけました。" },
