    "conform":      { example: "New employees are expected to conform to the company's professional standards and code of conduct.", exampleJa: "新入社員は会社のプロフェッショナル基準と行動規範に従うことが期待されています。" },
    "conformity":   { example: "Social pressure to conformity can stifle individual creativity and independent thinking.", exampleJa: "社会的な同調圧力は個人の創造性と独立した思考を抑圧することがあります。" },
    "confront":     { example: "The counsellor gently encouraged her to confront the difficult feelings she had been avoiding.", exampleJa: "カウンセラーは彼女が避けていた困難な感情に向き合うよう優しく促しました。" },
    "confrontation": { example: "Avoiding confrontation may seem easier in the short term but rarely resolves the underlying issue.", exampleJa: "対立を避けることは短期的には楽に見えますが根本的な問題を解決することはほとんどありません。" },
    "congestion":   { example: "Congestion pricing schemes charge drivers extra to reduce traffic in busy city centres.", exampleJa: "混雑課金制度は賑やかな市街地の交通量を減らすためにドライバーに追加料金を課します。" },
    "congregate":   { example: "Fans began to congregate outside the stadium several hours before the match started.", exampleJa: "ファンたちは試合開始の数時間前にスタジアムの外に集まり始めました。" },
    "congregation": { example: "The entire congregation rose to sing the final hymn at the close of the service.", exampleJa: "礼拝の終わりに会衆全員が立ち上がって最後の賛美歌を歌いました。" },
    "conjunction":  { example: "Coordinating conjunctions such as 'and', 'but', and 'or' link clauses of equal importance.", exampleJa: "「and」「but」「or」などの等位接続詞は同等の重要性を持つ節をつなぎます。" },
    "conjunctivitis": { example: "Conjunctivitis is highly contagious and spreads easily through direct hand-to-eye contact.", exampleJa: "結膜炎は感染力が非常に高く手から目への直接接触で容易に広がります。" },
    "connotation":  { example: "The word 'slim' has a positive connotation, while 'scrawny' sounds more critical.", exampleJa: "「slim（スリムな）」という言葉はポジティブな含意を持ち、「scrawny」はより批判的に聞こえます。" },
    "conquer":      { example: "Napoleon attempted to conquer the whole of Europe during the early nineteenth century.", exampleJa: "ナポレオンは19世紀初頭にヨーロッパ全土を征服しようとしました。" },
    "conquest":     { example: "The Spanish conquest of the Americas brought vast wealth but caused immense suffering.", exampleJa: "スペインによるアメリカ大陸の征服は膨大な富をもたらしましたが巨大な苦しみも引き起こしました。" },
    "conscience":   { example: "He could not ignore the persistent voice of his conscience telling him to speak the truth.", exampleJa: "彼は真実を語るよう促す自分の良心の声を無視することができませんでした。" },
    "conscientious": { example: "She was one of the most conscientious workers in the office, checking everything twice.", exampleJa: "彼女はすべてを二度確認するオフィスで最も良心的な労働者の一人でした。" },
    "conscript":    { example: "During the war, all men aged eighteen to forty were conscripted into the national army.", exampleJa: "戦争中に18歳から40歳のすべての男性が国軍に徴兵されました。" },
    "consecutive":  { example: "The athlete won three consecutive Olympic gold medals in the same track event.", exampleJa: "そのアスリートは同じ陸上競技種目で3回連続のオリンピック金メダルを獲得しました。" },
    "consensus":    { example: "The committee reached a broad consensus on the new environmental protection regulations.", exampleJa: "委員会は新しい環境保護規制について幅広い合意に達しました。" },
    "conservation of energy": { example: "The conservation of energy law states that energy can neither be created nor destroyed.", exampleJa: "エネルギー保存の法則はエネルギーは生成も消滅もできないと述べています。" },
    "conservatism": { example: "Political conservatism generally favours tradition, stability, and gradual rather than rapid change.", exampleJa: "政治的保守主義は一般的に伝統、安定、急激ではなく漸進的な変化を好みます。" },
    "conserve":     { example: "Turning off lights when leaving a room is one of the simplest ways to conserve energy.", exampleJa: "部屋を出るときに電気を消すことはエネルギーを節約する最も簡単な方法の一つです。" },
