    "consolation":  { example: "Although she finished second, the silver medal was a consolation after years of training.", exampleJa: "2位で終わりましたが銀メダルは何年もの訓練の後の慰めになりました。" },
    "console":      { example: "He tried to console his friend after she learned she had failed the important examination.", exampleJa: "彼は友人が重要な試験に落ちたと知った後、彼女を慰めようとしました。" },
    "consolidate":  { example: "The company decided to consolidate its four offices into a single new headquarters.", exampleJa: "会社は4つのオフィスを1つの新しい本社に統合することを決定しました。" },
    "consolidation": { example: "The consolidation of several smaller banks into one large institution reduced competition.", exampleJa: "いくつかの小さな銀行を1つの大きな機関に統合することで競争が減少しました。" },
    "conspiracy":   { example: "The government dismissed the claims as an unfounded and dangerous conspiracy theory.", exampleJa: "政府はその主張を根拠のない危険な陰謀論として退けました。" },
    "conspire":     { example: "Evidence suggested that two senior directors had conspired to manipulate the company accounts.", exampleJa: "証拠は2人の上級取締役が会社の会計を操作するために共謀していたことを示唆していました。" },
    "constituency": { example: "The politician returned to her constituency every weekend to meet and listen to local residents.", exampleJa: "その政治家は地元の住民に会い話を聞くために毎週末選挙区に戻りました。" },
    "constitute":   { example: "The new regulations constitute a significant shift in how the financial industry is governed.", exampleJa: "新しい規制は金融業界がどのように規制されるかの大きな転換を意味します。" },
    "constitutional": { example: "Freedom of expression is a fundamental constitutional right in most democratic societies.", exampleJa: "表現の自由はほとんどの民主主義社会における基本的な憲法上の権利です。" },
    "constitutionalism": { example: "Constitutionalism ensures that government authority is limited and defined by the law.", exampleJa: "立憲主義は政府の権限が法律によって制限され定義されることを確保します。" },
    "constraint":   { example: "Budget constraints forced the team to find creative ways to deliver the project on time.", exampleJa: "予算の制約によりチームはプロジェクトを時間通りに納品するための創造的な方法を見つけることを強いられました。" },

  // ── level-2 batch 12a (501–750) ─────────────────────
    "constructive": { example: "She welcomed constructive criticism because it helped her improve her writing.", exampleJa: "彼女は文章力を向上させるのに役立つため建設的な批評を歓迎しました。" },
