    "cooperative":  { example: "A cooperative business model gives all employees a share in the company's profits.", exampleJa: "協同組合型のビジネスモデルはすべての従業員に会社の利益の分配を与えます。" },
    "coordination": { example: "Good hand-eye coordination is essential for sports like tennis and cricket.", exampleJa: "良好な手と目の協調はテニスやクリケットなどのスポーツに不可欠です。" },
    "cordial":      { example: "Despite competing interests, both parties maintained a cordial and professional relationship.", exampleJa: "競合する利害関係にもかかわらず双方は和やかでプロフェッショナルな関係を維持しました。" },
    "cordially":    { example: "All guests were cordially invited to the reception following the award ceremony.", exampleJa: "すべてのゲストが授賞式後のレセプションに心から招待されました。" },
    "corporal":     { example: "Corporal punishment in schools has been banned in many countries as harmful to children.", exampleJa: "学校での体罰は子どもに有害として多くの国で禁止されています。" },
    "correlation":  { example: "Research showed a strong correlation between exercise frequency and reported happiness.", exampleJa: "研究は運動頻度と報告された幸福感の間に強い相関関係があることを示しました。" },
    "corruptible":  { example: "Even officials who start with good intentions can become corruptible under pressure.", exampleJa: "良い意図で始めた役人でさえ、プレッシャーの下で腐敗しやすくなることがあります。" },
    "corruption":   { example: "Widespread corruption in the justice system eroded public trust in the government.", exampleJa: "司法制度における蔓延した腐敗が政府への国民の信頼を損ないました。" },
    "cosmology":    { example: "Cosmology attempts to explain the origin, structure, and ultimate fate of the universe.", exampleJa: "宇宙論は宇宙の起源、構造、最終的な運命を説明しようとします。" },
    "cosmonaut":    { example: "The Russian cosmonaut spent six months aboard the international space station.", exampleJa: "ロシアの宇宙飛行士は国際宇宙ステーションに6ヶ月間滞在しました。" },
    "cosmopolitan": { example: "Tokyo is one of the most cosmopolitan cities in the world, blending cultures from everywhere.", exampleJa: "東京は世界中の文化が融合する世界で最もコスモポリタンな都市の一つです。" },
    "cosmos":       { example: "Scientists use powerful telescopes to study the farthest reaches of the cosmos.", exampleJa: "科学者たちは宇宙の最も遠い端を研究するために強力な望遠鏡を使用しています。" },
