    "deterrence":   { example: "Nuclear deterrence rests on the assumption that a threat of retaliation prevents attack.", exampleJa: "核抑止は報復の脅威が攻撃を防ぐという前提に基づいています。" },
    "deterrent":    { example: "Strict financial penalties serve as a strong deterrent against corporate tax evasion.", exampleJa: "厳格な財政的ペナルティは企業の脱税に対する強力な抑止力として機能します。" },
    "detract":      { example: "The ugly signage around the entrance detracted from the building's otherwise elegant appearance.", exampleJa: "入口周辺の見苦しい看板は建物の他の部分の優雅な外観を損ないました。" },
    "devalue":      { example: "The central bank decided to devalue the currency to boost export competitiveness.", exampleJa: "中央銀行は輸出競争力を高めるために通貨を切り下げることを決定しました。" },
    "deviance":     { example: "Sociologists study deviance to understand why individuals break established social norms.", exampleJa: "社会学者は個人がなぜ確立された社会規範を破るのかを理解するために逸脱を研究します。" },
    "devise":       { example: "Engineers devised a simple but ingenious solution to the long-standing technical problem.", exampleJa: "エンジニアたちは長年の技術的問題に対してシンプルだが独創的な解決策を考案しました。" },
    "devotee":      { example: "A lifelong devotee of classical music, she never missed a concert at the opera house.", exampleJa: "生涯を通じたクラシック音楽の熱狂的ファンとして彼女はオペラハウスのコンサートに一度も欠席しませんでした。" },
    "dexterity":    { example: "Surgeons require exceptional manual dexterity to perform delicate operations.", exampleJa: "外科医は繊細な手術を行うために優れた手指の器用さを必要とします。" },
    "diabolical":   { example: "The villain in the novel concocted a diabolical plan to seize control of the entire city.", exampleJa: "小説の悪役は都市全体の支配権を掌握するための悪魔のような計画を企てました。" },
    "diagnostic":   { example: "The engineer ran a full diagnostic check on the system before restarting it.", exampleJa: "エンジニアはシステムを再起動する前に完全な診断チェックを実行しました。" },
    "diametrically": { example: "The two candidates held diametrically opposed views on immigration policy.", exampleJa: "2人の候補者は移民政策について正反対の意見を持っていました。" },
    "diaphragm":    { example: "Deep breathing exercises train the diaphragm and can reduce anxiety significantly.", exampleJa: "深呼吸の運動は横隔膜を鍛え不安を大幅に軽減することができます。" },
    "dictaphone":   { example: "The journalist used a dictaphone to record the interview for accurate transcription later.", exampleJa: "ジャーナリストは後での正確な書き起こしのためにインタビューを録音するためにディクタフォンを使いました。" },
    "dictate":      { example: "Market conditions often dictate the pace at which new products are launched.", exampleJa: "市場の状況はしばしば新製品が発売されるペースを左右します。" },
    "dictatorship": { example: "Life under the dictatorship was marked by fear, surveillance, and suppression of dissent.", exampleJa: "独裁政権下での生活は恐怖、監視、反対意見の弾圧が特徴でした。" },
    "diction":      { example: "An actor's clear diction ensures every word in the performance reaches the back row.", exampleJa: "俳優の明確な話し方はパフォーマンスのすべての言葉が後列まで届くことを確保します。" },
    "differential": { example: "A significant wage differential between men and women still exists in many industries.", exampleJa: "多くの産業で男性と女性の間にまだ大きな賃金格差が存在します。" },
    "differentiate": { example: "The new model is hard to differentiate from last year's version without close inspection.", exampleJa: "新モデルは注意深く検査しなければ昨年のバージョンと区別することが難しいです。" },
    "differentiation": { example: "Product differentiation helps companies stand out in a crowded and competitive market.", exampleJa: "製品差別化は企業が混雑した競争の激しい市場で際立つのに役立ちます。" },
    "diffuse":      { example: "The spokesperson tried to diffuse tension in the room with a carefully chosen remark.", exampleJa: "スポークスパーソンは慎重に選んだ発言で部屋の緊張を和らげようとしました。" },
