    "digestion":    { example: "Eating slowly and mindfully improves digestion and helps avoid bloating.", exampleJa: "ゆっくりと意識的に食べることは消化を改善し膨満感を防ぐのに役立ちます。" },
    "diligence":    { example: "Success in language learning depends more on diligence than on natural talent.", exampleJa: "語学学習の成功は天賦の才能よりも勤勉さに依存しています。" },
    "diminish":     { example: "Over time, the memory of that painful day gradually diminished but never fully disappeared.", exampleJa: "時間が経つにつれてその辛い日の記憶は徐々に薄れましたが完全に消えることはありませんでした。" },
    "diminuendo":   { example: "The piece ended with a long diminuendo, fading to near silence.", exampleJa: "曲はほぼ無音になるまでゆっくりと消えていく長いディミヌエンドで終わりました。" },
    "diminutive":   { example: "Despite her diminutive stature, she commanded respect in every room she entered.", exampleJa: "小柄な体格にもかかわらず彼女は入るすべての部屋で尊敬を集めました。" },

  // ── level-2 batch 12b (751–1000) ────────────────────
    "diplomacy":    { example: "Skilled diplomacy helped resolve the border dispute without resort to military force.", exampleJa: "巧みな外交が軍事力に頼らずに国境紛争の解決に役立ちました。" },
