    "distinct":     { example: "Each region of the country has a distinct culinary tradition and flavour profile.", exampleJa: "その国の各地域には独自の料理の伝統と風味のプロファイルがあります。" },
    "distinction":  { example: "She graduated with distinction, achieving the highest marks in her entire year group.", exampleJa: "彼女は優秀な成績で卒業し学年全体で最高得点を達成しました。" },
    "distort":      { example: "The documentary was accused of distorting the facts to fit a particular narrative.", exampleJa: "そのドキュメンタリーは特定のナラティブに合わせて事実を歪曲したとして非難されました。" },
    "distributed":  { example: "The company operates on a distributed model, with teams working across five continents.", exampleJa: "会社は5つの大陸にわたってチームが働く分散型モデルで運営されています。" },
    "distribution": { example: "Efficient distribution networks are critical to getting products to customers on time.", exampleJa: "効率的な流通ネットワークは製品を時間通りに顧客に届けるために重要です。" },
    "disturbance":  { example: "Police were called to deal with a disturbance outside the venue late at night.", exampleJa: "深夜に会場の外での騒動に対処するために警察が呼ばれました。" },
    "divergence":   { example: "The divergence between the two models' predictions grew larger over time.", exampleJa: "2つのモデルの予測間の乖離は時間の経過とともに大きくなりました。" },
    "diversification": { example: "Portfolio diversification reduces risk by spreading investments across different asset classes.", exampleJa: "ポートフォリオの分散化は投資を異なる資産クラスに広げることでリスクを軽減します。" },
    "diversify":    { example: "The company needs to diversify its revenue streams to reduce dependence on a single product.", exampleJa: "会社は単一製品への依存を減らすために収益の流れを多様化する必要があります。" },
    "dividend":     { example: "Long-term shareholders received a generous dividend at the end of the financial year.", exampleJa: "長期株主は会計年度末に手厚い配当を受け取りました。" },
