    "downbeat":     { example: "Despite a downbeat economic forecast, consumer confidence remained surprisingly high.", exampleJa: "暗い経済見通しにもかかわらず消費者信頼感は驚くほど高く維持されました。" },
    "downfall":     { example: "His obsession with secrecy was ultimately the downfall of his political career.", exampleJa: "秘密主義への執着が最終的に彼の政治キャリアの破滅となりました。" },
    "downplay":     { example: "The spokesperson tried to downplay the severity of the incident during the press conference.", exampleJa: "スポークスパーソンは記者会見で事件の深刻さを軽視しようとしました。" },
    "downright":    { example: "His behaviour at the meeting was downright rude and embarrassed the whole team.", exampleJa: "会議での彼の行動は全くもって無礼でチーム全体を恥ずかしい思いにさせました。" },
    "downsize":     { example: "The company had to downsize its workforce by fifteen percent to cut operating costs.", exampleJa: "会社は運営コストを削減するために従業員を15%削減しなければなりませんでした。" },
    "downsizing":   { example: "The downsizing process was handled sensitively to minimise disruption to remaining staff.", exampleJa: "人員削減のプロセスは残ったスタッフへの混乱を最小限に抑えるために慎重に処理されました。" },
    "downturm":     { example: "The global economic downturn led many companies to freeze hiring for over a year.", exampleJa: "世界的な経済の落ち込みにより多くの企業が1年以上採用を凍結しました。" },
    "dream analysis": { example: "Psychoanalysts use dream analysis to explore the unconscious mind of their patients.", exampleJa: "精神分析医は患者の無意識の心を探るために夢分析を使用します。" },
    "dreamlike":    { example: "The film's dreamlike visuals and haunting music created an unforgettable atmosphere.", exampleJa: "映画の夢幻的な映像と心に残る音楽が忘れられない雰囲気を作り出しました。" },
    "droplet":      { example: "Respiratory viruses spread through tiny droplets released when an infected person coughs.", exampleJa: "呼吸器系ウイルスは感染者が咳をしたときに放出される小さな飛沫を通じて広がります。" },
