    "dustproof":    { example: "The camera housing is dustproof and waterproof, making it ideal for field use.", exampleJa: "カメラのハウジングは防塵防水で、野外使用に理想的です。" },
    "duty-bound":   { example: "As a public servant, she felt duty-bound to report the financial irregularities she had discovered.", exampleJa: "公務員として彼女は発見した財務の不正を報告する義務があると感じました。" },
    "dynamics":     { example: "The dynamics of the team changed significantly after two senior members resigned.", exampleJa: "2人の上級メンバーが辞任した後、チームのダイナミクスは大きく変化しました。" },
    "dysentery":    { example: "Dysentery spreads through contaminated water and causes severe diarrhoea and dehydration.", exampleJa: "赤痢は汚染された水を通じて広がり重篤な下痢と脱水症状を引き起こします。" },
    "dysfunctional": { example: "A dysfunctional workplace culture leads to high staff turnover and low productivity.", exampleJa: "機能不全の職場文化は高い離職率と低い生産性につながります。" },
    "dyslexia":     { example: "Students with dyslexia often benefit from audio-based learning materials and extra reading time.", exampleJa: "難読症の生徒はしばしば音声ベースの学習教材と追加の読書時間から恩恵を受けます。" },
    "dyslexic":     { example: "Many dyslexic individuals are highly creative and excel in visual and spatial thinking.", exampleJa: "難読症の多くの人は非常に創造的で視覚的・空間的思考において優れています。" },
    "dystopian":    { example: "The novel imagines a dystopian future where technology controls every aspect of daily life.", exampleJa: "その小説はテクノロジーが日常生活のあらゆる側面を支配するディストピア的な未来を想像しています。" },
