    "fusion":       { example: "Nuclear fusion offers the potential to provide virtually unlimited clean energy.", exampleJa: "核融合は事実上無限のクリーンエネルギーを提供する可能性を持っています。" },
    "futures":      { example: "Commodity futures allow traders to lock in prices for goods to be delivered later.", exampleJa: "商品先物は取引者が後で引き渡される商品の価格を固定することを可能にします。" },
